#include <stdio.h>
#include <limits.h>

int divideIntegers(int numerator, int denominator) {
    int sign = ((numerator < 0) ^ (denominator < 0)) ? -1 : 1;
    long long num = numerator < 0 ? -(long long)numerator : (long long)numerator;
    long long den = denominator < 0 ? -(long long)denominator : (long long)denominator;
    long long result = 0;
    while (num >= den) {
        long long temp = den;
        long long multiple = 1;
        while (num >= (temp << 1)) {
            temp <<= 1;
            multiple <<= 1;
        }
        num -= temp;
        result += multiple;
    }
    result = sign * result;
    if (result > INT_MAX) return INT_MAX;
    if (result < INT_MIN) return INT_MIN;
    return (int)result;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int numerator, denominator;
        scanf("%d %d", &numerator, &denominator);
        printf("%d\n", divideIntegers(numerator, denominator));
    }
    return 0;
}

