import java.io.*;
import java.util.*;

public class Main {
    private static final int INT_MAX = Integer.MAX_VALUE;
    private static final int INT_MIN = Integer.MIN_VALUE;

    private static int divideIntegers(int numerator, int denominator) {
        int sign = ((numerator < 0) ^ (denominator < 0)) ? -1 : 1;
        long num = numerator < 0 ? -(long) numerator : (long) numerator;
        long den = denominator < 0 ? -(long) denominator : (long) denominator;
        long res = 0;
        while (num >= den) {
            long temp = den;
            long mul = 1;
            while (num >= (temp << 1)) {
                temp <<= 1;
                mul <<= 1;
            }
            num -= temp;
            res += mul;
        }
        res = sign * res;
        if (res > INT_MAX) return INT_MAX;
        if (res < INT_MIN) return INT_MIN;
        return (int) res;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; ++t) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int numerator = Integer.parseInt(st.nextToken());
            int denominator = Integer.parseInt(st.nextToken());
            sb.append(divideIntegers(numerator, denominator)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

